const ESTIMATE_MEASUREMENT_BASE_BY_ID = ESTIMATE_MEASUREMENT_BASES.reduce((acc,b)=>{acc[b.id]=b;return acc;},{});
const estimateMeasurementBasisMeta = (basis) => ESTIMATE_MEASUREMENT_BASE_BY_ID[basis] || ESTIMATE_MEASUREMENT_BASE_BY_ID.manual;
const PROJECT_MEASUREMENT_SOURCE_TYPES = ['Проект','Фактический ручной','Фактический из фото','Экспликация','Ведомость окон/дверей','Уточнённый'];
const PROJECT_MEASUREMENT_DOC_TYPES = ['Проект','Обмер','Экспликация','Ведомость окон','Ведомость дверей','Фото обмера','Рукописный обмер','Прочее'];
const PROJECT_MEASUREMENT_STATUSES = ['Черновик','На проверке','Принято','Отклонено'];
const suggestEstimateMeasurementBasis = (it={}, sectionName='') => {
  const text = estimateTextKey([sectionName, it.section, it.name].filter(Boolean).join(' '));
  const unit = _normalizeUnit(normalizeMeasure(1, it.unit).unit || it.unit || '');
  if (estimateTextHasAny(text, ['демонтаж','разбор','разборка','снятие','удаление'])) return 'demolition';
  if (unit === 'м') return 'linear';
  if (unit === 'шт') {
    if (estimateTextHasAny(text, ['окно','оконный блок','подоконник'])) return 'window_count';
    if (estimateTextHasAny(text, ['двер','дверной блок','полотно'])) return 'door_count';
    if (estimateTextHasAny(text, ['розет','выключател','светильник','точк','прибор','радиатор','решетк','унитаз','раковин','смесител','коробка ответвительная'])) return 'point';
    return 'manual';
  }
  if (unit !== 'м2') return 'manual';
  const hasFloorWord = /(^| )пол( |$)/.test(text) || /(^| )пола( |$)/.test(text) || /(^| )полы( |$)/.test(text);
  const hasWindowWord = estimateTextHasAny(text, ['окно','окон','оконный блок','оконные блоки','стеклопакет']);
  const hasDoorWord = estimateTextHasAny(text, ['двер','дверной блок','дверные блоки','полотно']);
  const hasRevealWord = estimateTextHasAny(text, ['откос']);
  const hasOpeningBlockWord = estimateTextHasAny(text, ['проем','проём','блок','блоков','замена']);
  const hasWallWord = estimateTextHasAny(text, ['стен','перегород','фасад']);
  const hasCeilingWord = estimateTextHasAny(text, ['потолок','потолк','потолоч']);
  if (hasRevealWord && hasWindowWord && hasDoorWord) return 'opening_reveals';
  if (estimateTextHasAny(text, ['оконный откос','откос окон','откосы окон','оконные откосы'])) return 'window_reveals';
  if (estimateTextHasAny(text, ['дверной откос','откос двер','откосы двер','дверные откосы'])) return 'door_reveals';
  if (hasWindowWord && hasDoorWord && hasOpeningBlockWord) return 'openings_area';
  if (hasWindowWord && hasOpeningBlockWord) return 'window_area';
  if (hasDoorWord && hasOpeningBlockWord) return 'door_area';
  if (hasWallWord && hasCeilingWord) return 'wall_ceiling_area';
  if (estimateTextHasAny(text, ['потолок','потолк','потолоч','подвесной потолок','натяжной потолок'])) return 'ceiling_area';
  if (hasFloorWord || estimateTextHasAny(text, ['стяжк','плитка пола','ламинат','линолеум','покрытие пола'])) return 'floor_area';
  if (estimateTextHasAny(text, ['окно','оконный блок','оконные блоки','замена окон','стеклопакет'])) return 'window_area';
  if (estimateTextHasAny(text, ['двер','дверной блок','дверные блоки','полотно','замена двер'])) return 'door_area';
  if (estimateTextHasAny(text, ['штукатур','шпатлев','шпаклев','окраск','обои','облицовка стен','стен','перегород','фасад'])) return 'wall_net_area';
  return 'manual';
};
const estimateMeasurementBasisOf = (it={}, sectionName='') => (it.measurementBasis && ESTIMATE_MEASUREMENT_BASE_BY_ID[it.measurementBasis]) ? it.measurementBasis : suggestEstimateMeasurementBasis(it, sectionName);
const enrichEstimateMeasurementBasis = (sections=[]) => (sections||[]).map(section => ({
  ...section,
  items: (section.items||[]).map(item => {
    const itemType = normalizeEstimateItemType(item, section.name);
    return {
      ...item,
      itemType: item.itemType || itemType,
      measurementBasis: itemType === 'work' ? (item.measurementBasis || suggestEstimateMeasurementBasis(item, section.name)) : 'manual'
    };
  })
}));
const estimateItemWorkSum = (it) => (it?.isImported ? toNum(it?.priceWork) : toNum(it?.quantity) * toNum(it?.priceWork));
const estimateItemMaterialSum = (it) => (it?.isImported ? toNum(it?.priceMaterial) : toNum(it?.quantity) * toNum(it?.priceMaterial));
const estimateItemTotal = (it) => estimateItemWorkSum(it) + estimateItemMaterialSum(it);
const estimateItemDoneTotal = (it) => {
  const q = toNum(it?.quantity);
  const d = toNum(it?.doneQuantity);
  if (it?.isImported) return q > 0 ? (d / q) * estimateItemTotal(it) : 0;
  return d * (toNum(it?.priceWork) + toNum(it?.priceMaterial));
};
// Нормализация ГЭСН-единиц: «100 м²» × 0.23 → «м²» × 23, «1000 шт» × 0.5 → «шт» × 500.
// Это для УДОБНОГО показа мастеру/прорабу/заказчику. В БД хранится исходник.
const normalizeMeasure = (qty, unit) => {
  if(!unit) return {qty: toNum(qty), unit: unit||'', factor: 1};
  // Ищем число-множитель в начале строки: "100 м²", "1000 шт", "10 м³", "100м2"
  const m = String(unit).trim().match(/^(\d{2,})\s*(.+)$/);
  if(!m) return {qty: toNum(qty), unit, factor: 1};
  const factor = parseInt(m[1], 10);
  if(factor < 10) return {qty: toNum(qty), unit, factor: 1};
  return {qty: toNum(qty) * factor, unit: m[2].trim(), factor};
};
// Обратное преобразование: пользователь ввёл 23 м², а unit смета «100 м²» — сохраняем 0.23
const denormalizeMeasure = (qty, unit) => {
  const {factor} = normalizeMeasure(1, unit);
  if(factor <= 1) return toNum(qty);
  return toNum(qty) / factor;
};
// Красивое форматирование "qty unit" с автонормализацией
const fmtMeasure = (qty, unit) => {
  const n = normalizeMeasure(qty, unit);
  const q = n.qty;
  const qStr = Math.abs(q - Math.round(q)) < 0.001 ? String(Math.round(q)) : q.toLocaleString('ru-RU', {maximumFractionDigits: 3});
  return qStr + ' ' + (n.unit||'');
};
const daysInMonth = Array.from({length: 31}, (_, i) => String(i + 1));

const requestPushPermission = async () => {
  if (!('Notification' in window)) return false;
  if (Notification.permission === 'granted') return true;
  const permission = await Notification.requestPermission();
  return permission === 'granted';
};

const sendPushNotification = (title, body) => {
  if (Notification.permission === 'granted') {
    new Notification('🏗️ ' + title, { body, icon: '/favicon.ico' });
  }
};

const doPrint = (content) => {
  const iframe = document.createElement('iframe');
  iframe.style.cssText = 'position:fixed;top:0;left:0;width:0;height:0;border:none;';
  document.body.appendChild(iframe);
  const doc = iframe.contentDocument || iframe.contentWindow.document;
  doc.open();
  doc.write('<!DOCTYPE html><html><head><meta charset="utf-8"><style>body{font-family:Arial,sans-serif;padding:30px;font-size:12px;color:#000}table{width:100%;border-collapse:collapse;margin:15px 0}td,th{border:1px solid #333;padding:6px;text-align:left}th{background:#f5f5f5}h2{text-align:center;margin-bottom:5px}p{margin:4px 0}.signatures{display:flex;justify-content:space-between;margin-top:40px}.sig{text-align:center;width:30%}.sig-line{border-top:1px solid #333;margin-top:30px;padding-top:5px}@media print{body{padding:15px}}</style></head><body>'+content+'</body></html>');
  doc.close();
  setTimeout(() => { iframe.contentWindow.focus(); iframe.contentWindow.print(); setTimeout(() => document.body.removeChild(iframe), 2000); }, 300);
};

const generateQR = (text) => {
  const size = 150;
  const url = `https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(text)}`;
  return url;
};

