  useEffect(() => {
    if (typeof document !== 'undefined') document.documentElement.dataset.theme = darkMode ? 'dark' : 'light';
    try { localStorage.setItem('darkMode', darkMode ? '1' : '0'); } catch(e) {}
  }, [darkMode]);
