      return '<tr>'
        + '<td style="color:'+color+';font-weight:700">'+docEsc(r.status)+'</td>'
        + '<td>'+docEsc(r.packageName)+'</td>'
        + '<td>'+docEsc(r.sectionName)+'</td>'
