    if (!a || !b) return 0;
    if (a === b) return 1;
    if (a.includes(b) || b.includes(a)) return 0.92;
    const aw = a.split(' ').filter(w=>w.length>3);
    const bw = b.split(' ').filter(w=>w.length>3);
