    const rows=materialReconciliationRows(projectName);
    const normRows=estimateWorkNormRequirementRows(projectName);
    const normCtrl=materialNormControlSummaryForProject(projectName);
    let html='<style>.mr-tbl{border-collapse:collapse;width:100%;font-size:10.5px;margin:8px 0}.mr-tbl th,.mr-tbl td{border:1px solid #333;padding:5px 6px}.mr-tbl th{background:#f3f4f6}.mr-need{background:#fef3c7;font-weight:700}.mr-over{background:#dbeafe}.mr-out{background:#fee2e2}.mr-ok{background:#dcfce7}</style>';
    html+='<h2 style="text-align:center;margin:6px 0">ВЕДОМОСТЬ ПОТРЕБНОСТИ МАТЕРИАЛОВ</h2>';
    html+='<p style="text-align:center;font-size:11px;color:#444">по смете объекта (план / заявки / в пути / накладные / поставки / перемещения / выдано / списано / остаток)</p>';
    html+='<p style="font-size:12px"><b>Объект:</b> '+projectName+' · <b>Подрядчик:</b> '+orgName+'</p>';
    if (activeEsts.length===0) html+='<p style="color:#dc2626;font-size:12px;text-align:center;padding:14px">⚠️ Смета не загружена — план посчитать невозможно</p>';
    if (rows.length===0) html+='<p style="text-align:center;color:#888;font-size:11px;padding:14px">Материалов в смете нет</p>';
	    else {
		      html+='<table class="mr-tbl"><tr><th>№</th><th>Материал</th><th>Раздел</th><th>Ед.</th><th>План</th><th>В заявках</th><th>В пути</th><th>Накладные</th><th>Поставки</th><th>Перемещено</th><th>Всего получено</th><th>Выдано</th><th>Списано</th><th>У мастеров</th><th>Остаток склада</th><th>Расчётный остаток</th><th>Расхождение</th><th>Докупить</th><th>Статус</th></tr>';
	      rows.forEach((r,i)=>{const cls=r.stockMismatch?'mr-out':r.issued>0&&r.usedWithoutIssue>0?'mr-out':r.isOutsideEstimate?'mr-out':r.toBuy>0?'mr-need':r.over>0?'mr-over':'mr-ok';const status=r.stockMismatch?'расхождение склада '+r.stockDiff.toLocaleString('ru-RU'):r.issued>0&&r.usedWithoutIssue>0?'списано сверх выдачи '+r.usedWithoutIssue.toLocaleString('ru-RU'):r.isOutsideEstimate?'вне сметы '+r.coveredWithPipeline.toLocaleString('ru-RU'):r.toBuy>0?'докупить '+r.toBuy.toLocaleString('ru-RU'):r.shortage>0?'закрывается заявками/поставками':r.masterBalance>0?'у мастеров '+r.masterBalance.toLocaleString('ru-RU'):r.over>0?'сверх '+r.over.toLocaleString('ru-RU'):'закрыто';html+='<tr class="'+cls+'"><td>'+(i+1)+'</td><td>'+r.name+(r.unitMismatch?' ⚠ ед.изм.':'')+'</td><td>'+(r.sections||[]).join(', ')+'</td><td>'+r.unit+'</td><td>'+r.planQty.toLocaleString('ru-RU')+'</td><td>'+r.requested.toLocaleString('ru-RU')+'</td><td>'+r.inTransit.toLocaleString('ru-RU')+'</td><td>'+r.invoiceReceived.toLocaleString('ru-RU')+'</td><td>'+r.supplyReceived.toLocaleString('ru-RU')+'</td><td>'+r.movedNet.toLocaleString('ru-RU')+'</td><td>'+r.supplied.toLocaleString('ru-RU')+'</td><td>'+r.issued.toLocaleString('ru-RU')+'</td><td>'+r.used.toLocaleString('ru-RU')+'</td><td>'+r.masterBalance.toLocaleString('ru-RU')+'</td><td>'+r.stock.toLocaleString('ru-RU')+'</td><td>'+r.expectedStock.toLocaleString('ru-RU')+'</td><td>'+r.stockDiff.toLocaleString('ru-RU')+'</td><td>'+r.toBuy.toLocaleString('ru-RU')+'</td><td>'+status+'</td></tr>';});
      const totalSum=rows.reduce((s,r)=>s+(r.planSum||0),0);
      html+='<tr style="background:#f3f4f6"><td colspan="4"><b>ИТОГО плановая стоимость материалов:</b></td><td colspan="15"><b>'+Math.round(totalSum).toLocaleString('ru-RU')+' ₽</b></td></tr>';
	      html+='</table>';
	    }
	    if (normRows.length>0) {
	      html+='<h3 style="font-size:13px;margin:18px 0 6px">Нормативная потребность по работам</h3>';
	      html+='<p style="font-size:10px;color:#666;margin:0 0 6px">Это подсказка для сметчика/снабжения: материалы рассчитаны из строк типа «Работа» по типовым нормам. Они не списываются и не попадают в закупку автоматически, пока не заведены строками типа «Материал».</p>';
	      html+='<table class="mr-tbl"><tr><th>№</th><th>Материал по норме</th><th>Ед.</th><th>Потребность</th><th>Работы-источники</th><th>Норма</th></tr>';
	      normRows.forEach((r,i)=>{html+='<tr><td>'+(i+1)+'</td><td>'+r.name+'</td><td>'+r.unit+'</td><td>'+r.planQty.toLocaleString('ru-RU')+'</td><td>'+r.works.slice(0,4).map(w=>w.name).join('; ')+(r.works.length>4?' …':'')+'</td><td>'+r.normSources.join('; ')+'</td></tr>';});
	      html+='</table>';
	    }
	    if (normCtrl.overRows.length>0 || normCtrl.withoutNormRows.length>0) {
	      html+='<h3 style="font-size:13px;margin:18px 0 6px">Контроль списания по нормам</h3>';
	      html+='<p style="font-size:10px;color:#666;margin:0 0 6px">Перерасход требует проверки прорабом/сметчиком. Строки без нормы означают, что материал списали, но система не нашла правило расхода.</p>';
	      html+='<table class="mr-tbl"><tr><th>№</th><th>Материал</th><th>Ед.</th><th>Факт списания</th><th>Норма</th><th>Отклонение</th><th>Работы</th><th>Статус</th></tr>';
	      [...normCtrl.overRows,...normCtrl.withoutNormRows.filter(r=>!normCtrl.overRows.some(o=>o.key===r.key))].forEach((r,i)=>{
	        const over=r.overQty>0;
	        const cls=over?'mr-out':'mr-need';
	        const deviation=over?('+'+r.overQty.toLocaleString('ru-RU')):('без нормы '+r.withoutNormQty.toLocaleString('ru-RU'));
	        html+='<tr class="'+cls+'"><td>'+(i+1)+'</td><td>'+r.name+'</td><td>'+r.unit+'</td><td>'+r.qty.toLocaleString('ru-RU')+'</td><td>'+(r.normQty>0?r.normQty.toLocaleString('ru-RU'):'—')+'</td><td>'+deviation+'</td><td>'+r.works.slice(0,4).map(w=>w.workName).join('; ')+(r.works.length>4?' …':'')+'</td><td>'+(over?'проверить перерасход':'завести/уточнить норму')+'</td></tr>';
	      });
	      html+='</table>';
	    }
    html+='<div style="margin-top:24px;display:grid;grid-template-columns:1fr 1fr;gap:20px">';
    html+='<div><div style="font-size:11px;font-weight:600;margin-bottom:30px">Сметчик / производитель работ:</div><div style="border-bottom:1px solid #333;min-height:18px"></div></div>';
