  const submitEstimateWorkDone = async (mi, displayQty) => {
    const project = projects.find(p=>p.id===Number(masterProjectId));
    const est = estimatesList.find(e=>Number(e.id)===Number(mi.estId));
    if (!project || !est) return;
    const qty = toNum(mi.quantity);
    const done = toNum(mi.doneQuantity);
    const raw = denormalizeMeasure(displayQty, mi.unit);
    if (raw <= done) { alert('Введите объём больше уже отправленного: сейчас '+fmtMeasure(done,mi.unit)); return; }
    if (qty>0 && raw>qty) { alert('План '+fmtMeasure(qty,mi.unit)+'. Нельзя поставить больше.'); return; }
    const workKey = estimateWorkKey(mi.estId, mi.sectionIdx, mi.itemIdx);
    const params = estimateWorkParams[workKey]||{};
    const deltaQty = Math.max(0, raw-done);
    const roomCheck = roomMeasurementCheck(project.name, params.roomId, params.surface||'Стены', deltaQty, mi.unit, mi.name);
    if (roomCheck?.over>0) { alert(roomMeasurementMessage(roomCheck)); return; }
    const usedMats = (estimateWorkMaterials[workKey]||[])
      .filter(m=>m.name)
      .map(m=>({name:m.name, quantity:toNum(m.quantity), unit:m.unit||'шт', normQuantity:toNum(m.normQuantity), normSource:m.normSource||'', autoNorm:!!m.autoNorm, overNorm:toNum(m.normQuantity)>0 && toNum(m.quantity)>toNum(m.normQuantity)*1.1}));
    for (const m of usedMats) {
      if (toNum(m.quantity)<=0) { alert('Укажите количество материала «'+m.name+'» или снимите галочку.'); return; }
    }
    const stockByName = materialAvailabilityMapForWork(project.name);
    const usageByName = {};
    usedMats.forEach(m=>{
      const key = materialNameKey(m.name);
      if (!usageByName[key]) usageByName[key] = {...m, quantity:0};
      usageByName[key].quantity += toNum(m.quantity);
    });
    for (const m of Object.values(usageByName)) {
      const stock = stockByName[materialNameKey(m.name)];
      if (!stock) { alert(isPersonalMaterialRole()?'Материал «'+m.name+'» не выдан вам или получение не подтверждено.':'Материал «'+m.name+'» не найден на складе объекта «'+project.name+'».'); return; }
      if (m.quantity > stock.quantity + 0.0001) { alert('Недостаточно материала «'+m.name+'»: выбрано '+fmtMeasure(m.quantity,m.unit)+', доступно '+fmtMeasure(stock.quantity,stock.unit)+'.'); return; }
    }
    const newSections = est.sections.map((s,si)=>si===mi.sectionIdx?{...s,items:s.items.map((it,ii)=>ii===mi.itemIdx?{...it,doneQuantity:raw}:it)}:s);
    const updated = {...est, sections:newSections, _workJournalMaterials:{[workKey]:usedMats}};
    const res = await fetch(API+'/estimates/'+est.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(updated)});
    if (!res.ok) {
      const er = await res.json().catch(()=>({}));
      alert('Не удалось отправить работу: '+(er.detail||res.status));
      return;
    }
    if (params.roomId) {
      await fetch(API+'/room-works',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({roomId:Number(params.roomId),project:project.name,roomName:params.roomName||roomCheck?.room?.name||'',masterId:user.id,masterName:user.name,description:mi.name,surface:params.surface||'Стены',unit:mi.unit,quantity:deltaQty,pricePerUnit:toNum(mi.priceWork||mi.price||0),total:deltaQty*toNum(mi.priceWork||mi.price||0),date:new Date().toISOString().split('T')[0],photoUrl:''})});
    }
    setEstimatesList(prev=>prev.map(e=>Number(e.id)===Number(est.id)?{...est,sections:newSections}:e));
    setEstimateDoneDrafts(prev=>{const next={...prev};delete next[workKey];return next;});
    setEstimateWorkMaterials(prev=>{const next={...prev};delete next[workKey];return next;});
    setEstimateWorkParams(prev=>{const next={...prev};delete next[workKey];return next;});
    await loadAll();
    notify('Работа отправлена в ЖПР: '+mi.name,'work');
    alert('Работа отправлена на проверку. Материалы списаны по выбранным нормам/количествам.');
  };

  const addMasterWorks = async () => {
    const project = projects.find(p=>p.id===Number(masterProjectId));
    if (!project) return;
    const pl = pricelists.find(p=>p.id===project.pricelistId);
    const coeff = pl?pl.coefficient:1.0;
    const now = new Date();
    let hasWork = false;
    const selectedEntries = Object.entries(selectedWorks).filter(([itemId,workData])=>{
      const item = pricelistItems.find(i=>i.id===Number(itemId));
      return item && workData.quantity && toNum(workData.quantity)>0;
    });
    if (!selectedEntries.length) { alert('Введите количество хотя бы для одной работы'); return; }
    const stockByName = materialAvailabilityMapForWork(project.name);
    const plannedUsage = {};
    for (const [itemId, workData] of selectedEntries) {
      const item = pricelistItems.find(i=>i.id===Number(itemId));
      const roomCheck = roomMeasurementCheck(project.name, workData.roomId, workData.surface||'Стены', workData.quantity, item.unit, item.name);
      if (roomCheck?.over>0) { alert(roomMeasurementMessage(roomCheck)); return; }
      for (const m of (workData.materials||[]).filter(mm=>mm.name)) {
        const qty = toNum(m.quantity);
        if (qty<=0) { alert('Укажите количество материала «'+m.name+'» для работы «'+item.name+'» или снимите галочку.'); return; }
        const key = materialNameKey(m.name);
        if (!plannedUsage[key]) plannedUsage[key] = {name:m.name, unit:m.unit||'шт', quantity:0};
        plannedUsage[key].quantity += qty;
      }
    }
    for (const u of Object.values(plannedUsage)) {
      const stock = stockByName[materialNameKey(u.name)];
      if (!stock) { alert(isPersonalMaterialRole()?'Материал «'+u.name+'» не выдан вам или получение не подтверждено.':'Материал «'+u.name+'» не найден на складе объекта «'+project.name+'». Сначала примите или переместите материал на объект.'); return; }
      if (u.quantity > stock.quantity + 0.0001) { alert('Недостаточно материала «'+u.name+'»: выбрано '+fmtMeasure(u.quantity,u.unit)+', доступно '+fmtMeasure(stock.quantity,stock.unit)+'.'); return; }
    }
    for (const [itemId,workData] of selectedEntries) {
      const item = pricelistItems.find(i=>i.id===Number(itemId));
      if (!item) continue;
      hasWork = true;
      const ppu = item.price*coeff;
      const workQty = toNum(workData.quantity);
      const total = workQty*ppu;
      const usedMats=(workData.materials||[]).filter(m=>m.name&&toNum(m.quantity)>0).map(m=>({name:m.name,quantity:toNum(m.quantity),unit:m.unit||'шт',normQuantity:toNum(m.normQuantity),normSource:m.normSource||'',autoNorm:!!m.autoNorm,overNorm:toNum(m.normQuantity)>0&&toNum(m.quantity)>toNum(m.normQuantity)*1.1}));
      const wjRes=await fetch(API+'/work-journal',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({masterId:user.id,masterName:user.name,project:project.name,description:item.name,unit:item.unit,quantity:workQty,pricePerUnit:ppu,total,date:now.toISOString().split('T')[0],comment:workData.comment||'',photoUrl:workData.photoUrl||'',materialsUsed:usedMats})});
      if(!wjRes.ok){const er=await wjRes.json().catch(()=>({}));alert('Не удалось списать материалы: '+(er.detail||'ошибка'));return;}
      if (workData.roomId) {
        await fetch(API+'/room-works',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({roomId:Number(workData.roomId),project:project.name,roomName:workData.roomName||'',masterId:user.id,masterName:user.name,description:item.name,surface:workData.surface||'Стены',unit:item.unit,quantity:workQty,pricePerUnit:ppu,total,date:now.toISOString().split('T')[0],photoUrl:workData.photoUrl||''})});
      }
    }
    if (!hasWork) { alert('Введите количество хотя бы для одной работы'); return; }
    notify(user.name+' отправил работы','work');
    await loadAll(); setSelectedWorks({}); setMasterProjectId(''); setPricelistItems([]);
    alert('Работы отправлены на проверку!');
  };

  // Открыть модалку для подтверждения с возможным пересчётом количества
  const openConfirmModal = (e) => {
    // Если pricePerUnit пустой — берём total/quantity (исторически некоторые записи без ppu)
    const fallbackPpu = (Number(e.pricePerUnit||0)===0 && Number(e.quantity||0)>0) ? (Number(e.total||0)/Number(e.quantity||0)) : Number(e.pricePerUnit||0);
    setConfirmingEntry({...e, _ppu: fallbackPpu});
    setConfirmAcceptedQty(String(e.quantity||''));
    setConfirmComment('');
  };

  const confirmJ = async (e, acceptedQty, comment) => {
    const planQty = toNum(e.quantity||0);
    const accepted = (acceptedQty===undefined||acceptedQty===null||acceptedQty==='')?planQty:toNum(acceptedQty);
    const ppu = Number(e._ppu||e.pricePerUnit||0) || (Number(e.total||0)/Math.max(1, planQty));
    const newTotal = Math.round(accepted * ppu);
    const body = {
      status:'Подтверждено',
      confirmedBy:user.name,
      confirmedAt:new Date().toISOString().split('T')[0],
      quantity: accepted,
      total: newTotal,
    };
    if(comment) body.comment = comment;
    await fetch(API+'/work-journal/'+e.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(body)});
    // Записываем в piecework (сдельные) — для расчёта зарплаты
    try {
      const alreadyPaid = (piecework||[]).some(pw=>Number(pw.workJournalId)===Number(e.id));
      if(!alreadyPaid && e.masterId && accepted>0 && ppu>0){
        await fetch(API+'/piecework',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({
          staffId:e.masterId,
          masterName:e.masterName||e.master_name||'',
          project:e.project||'',
          description:e.description||'',
          unit:e.unit||'',
          quantity:accepted,
          pricePerUnit:ppu,
          total:newTotal,
          date:new Date().toISOString().split('T')[0],
          workJournalId:e.id,
        })});
      }
    } catch(_){}
    await loadAll();
    await updateProjectProgress(e.project||"");
    setConfirmingEntry(null); setConfirmAcceptedQty(''); setConfirmComment('');
    const msg = (accepted<planQty)?('Принято '+accepted+' из '+planQty+' '+(e.unit||'')+' · '+e.description):'Работа подтверждена: '+e.description;
    notify(msg,'work'); addActivity(msg);
  };

