  const saveInlinePlItem = async (item) => {
    const data = inlineEditPlData.name ? inlineEditPlData : {...item,price:inlineEditPrice};
    if (!String(data.name||'').trim() || String(data.price||'').trim()==='') return;
    await fetch(API+'/pricelist-items/'+item.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({...item,...data,price:Number(data.price),pricelistId:selectedPricelist.id})});
    await loadPricelistItems(selectedPricelist.id);
    cancelInlinePlEdit();
  };

  const deletePlItem = async (id) => { await fetch(API+'/pricelist-items/'+id,{method:'DELETE'}); await loadPricelistItems(selectedPricelist.id); };

  const saveSupplier = async () => {
    if (!newSupplier.name) return;
    if (editingItem&&editingItem.id) await fetch(API+'/suppliers/'+editingItem.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(newSupplier)});
    else await fetch(API+'/suppliers',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(newSupplier)});
    await loadAll(); setNewSupplier({name:'',phone:'',email:'',specialization:'',category:'Сыпучие и бетон',rating:5.0,status:'Активный'}); setEditingItem(null); setShowForm(false);
  };

  const deleteSupplier = async (id) => { if (window.confirm('Удалить?')) { await fetch(API+'/suppliers/'+id,{method:'DELETE'}); await loadAll(); } };

  const renderSuppliersDirectory = () => {
    const canEditSuppliers = ['директор','зам_директора','кладовщик','снабженец'].includes(user.role);
    return (<div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'15px',gap:'8px',flexWrap:'wrap'}}>
        <div>
          <b style={{color:C.text,fontSize:'15px',fontWeight:'700'}}>🚚 Поставщики</b>
          <p style={{color:C.textSec,fontSize:'11px',margin:'2px 0 0'}}>Справочник поставщиков теперь находится внутри снабжения.</p>
        </div>
        {canEditSuppliers&&<div style={{display:'flex',gap:'6px',flexWrap:'wrap'}}>
          <button onClick={()=>{setSupplierInviteForm({presetName:'',presetCategory:'Сыпучие и бетон',supplierId:null,expiresInDays:14});setGeneratedInviteLink(null);setShowSupplierInviteModal(true);}} style={btnGr}><Plus size={14}/>🔗 Пригласить по ссылке</button>
          <button onClick={()=>{setShowForm(!showForm);setEditingItem(null);setNewSupplier({name:'',phone:'',email:'',specialization:'',category:'Сыпучие и бетон',rating:5.0,status:'Активный'});}} style={btnO}><Plus size={14}/>Добавить вручную</button>
        </div>}
      </div>
      {showForm&&canEditSuppliers&&(<div style={{...card,padding:'20px',marginBottom:'16px'}}>
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(190px,1fr))',gap:'10px'}}>
          <input placeholder="Название *" value={newSupplier.name} onChange={e=>setNewSupplier({...newSupplier,name:e.target.value})} style={{...inp,marginBottom:0}}/>
          <input placeholder="Телефон" value={newSupplier.phone} onChange={e=>setNewSupplier({...newSupplier,phone:e.target.value})} style={{...inp,marginBottom:0}}/>
          <input placeholder="Email" value={newSupplier.email} onChange={e=>setNewSupplier({...newSupplier,email:e.target.value})} style={{...inp,marginBottom:0}}/>
          <select value={newSupplier.category} onChange={e=>setNewSupplier({...newSupplier,category:e.target.value})} style={{...inp,marginBottom:0}}>{SUPPLIER_CATEGORIES.map(c=><option key={c}>{c}</option>)}</select>
          <input placeholder="Специализация" value={newSupplier.specialization} onChange={e=>setNewSupplier({...newSupplier,specialization:e.target.value})} style={{...inp,marginBottom:0}}/>
          <select value={newSupplier.status} onChange={e=>setNewSupplier({...newSupplier,status:e.target.value})} style={{...inp,marginBottom:0}}>{['Активный','Неактивный','Заблокирован'].map(s=><option key={s}>{s}</option>)}</select>
        </div>
        <div style={{display:'flex',gap:'8px',marginTop:'12px'}}><button onClick={saveSupplier} style={btnO}><Check size={14}/>{editingItem?'Сохранить':'Добавить'}</button><button onClick={()=>{setShowForm(false);setEditingItem(null);}} style={btnG}><X size={14}/>Отмена</button></div>
      </div>)}
      <div style={{position:'relative',marginBottom:'12px'}}>
        <Search size={14} style={{position:'absolute',left:'10px',top:'50%',transform:'translateY(-50%)',color:C.textMuted}}/>
        <input placeholder='🔍 Поиск поставщика' value={listSearch} onChange={e=>setListSearch(e.target.value)} style={{...inp,marginBottom:0,paddingLeft:'32px'}}/>
      </div>
      {SUPPLIER_CATEGORIES.map(cat=>{
        const catSuppliers=suppliers.filter(s=>s.category===cat&&matchSearch(listSearch,s.name,s.specialization,s.phone,s.email));
        if(catSuppliers.length===0) return null;
        return(<div key={cat} style={{marginBottom:'20px'}}>
          <div style={{display:'flex',alignItems:'center',gap:'8px',marginBottom:'10px',padding:'8px 12px',backgroundColor:C.bg,borderRadius:'8px',border:'1.5px solid '+C.border}}>
            <b style={{color:C.accent,fontSize:'13px'}}>{'🏭 '+cat}</b>
            <span style={{color:C.textSec,fontSize:'12px'}}>{'('+catSuppliers.length+')'}</span>
          </div>
          {catSuppliers.map(s=>(<div key={s.id} style={{...card,padding:'14px',marginBottom:'8px',marginLeft:'12px'}}>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',gap:'10px',flexWrap:'wrap'}}>
              <div><b style={{color:C.text,fontSize:'13px'}}>{s.name}</b><p style={{color:C.textSec,margin:'2px 0',fontSize:'12px'}}>{s.phone+(s.email?' · '+s.email:'')+(s.specialization?' · '+s.specialization:'')}</p><div style={{display:'flex',gap:'4px',marginTop:'4px'}}>{[1,2,3,4,5].map(star=>(<span key={star} style={{color:star<=s.rating?'#f59e0b':'#d1d5db',fontSize:'14px',cursor:canEditSuppliers?'pointer':'default'}} onClick={async()=>{if(!canEditSuppliers) return; await fetch(API+'/suppliers/'+s.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({...s,rating:star})});await loadAll();}}>★</span>))}</div></div>
              {canEditSuppliers&&<div style={{display:'flex',gap:'6px'}}>
                <button onClick={()=>{setEditingItem(s);setNewSupplier({...s});setShowForm(true);}} style={{...btnG,padding:'5px 10px'}}><Edit2 size={11}/></button>
                <button onClick={()=>deleteSupplier(s.id)} style={{...btnR,padding:'5px 10px'}}><Trash2 size={11}/></button>
              </div>}
            </div>
          </div>))}
        </div>);
      })}
      {suppliers.length===0&&<p style={{color:C.textMuted,textAlign:'center',padding:'30px'}}>Поставщиков нет</p>}
    </div>);
  };

  const saveRequest = async () => {
    const validItems = newRequest.items.filter(i=>i.materialName&&i.quantity);
    if (!validItems.length||!newRequest.project) return;
    for (const item of validItems) {
      await fetch(API+'/supply-requests',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({materialName:item.materialName,quantity:Number(item.quantity),unit:item.unit,project:newRequest.project,createdBy:user.name,date:new Date().toISOString().split('T')[0],notes:newRequest.notes,selectedSuppliers:newRequest.selectedSuppliers,category:newRequest.category||''})});
    }
    notify('Новая заявка на материалы','supply');
    await loadAll(); setNewRequest({items:[{materialName:'',quantity:'',unit:'шт'}],project:'',notes:'',selectedSuppliers:[],category:''}); setShowForm(false);
  };

  const cancelRequest = async (id) => { await fetch(API+'/supply-requests/'+id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:'Отменена'})}); await loadAll(); };

  // === Helpers для раздела «🛒 Снабжение» (Сн.1) ===
  const createSupplyReq = async () => {
    const valid = (newSupplyReq.items||[]).filter(i=>i.materialName && Number(i.quantity)>0);
    if (!valid.length || !newSupplyReq.project) {
      alert('Заполните хотя бы одну строку (материал + кол-во) и выберите объект');
      return;
    }
    // ОДНА заявка со ВСЕМИ позициями (items[])
    // backend пакует все позиции в items_json, в material_name пишется агрегат для совместимости
    const itemsPayload = valid.map(it => ({
      materialName: it.materialName,
      quantity: Number(it.quantity),
      unit: it.unit || 'шт'
    }));
    const r = await fetch(API+'/supply-requests', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({
        // Для совместимости со старыми полями — пишем первую позицию
        materialName: itemsPayload[0].materialName,
        quantity: itemsPayload[0].quantity,
        unit: itemsPayload[0].unit,
        // Главное — массив всех позиций
        items: itemsPayload,
        project: newSupplyReq.project,
        createdBy: user.name,
        date: new Date().toISOString().split('T')[0],
        notes: newSupplyReq.notes || '',
        category: newSupplyReq.category || '',
        urgency: newSupplyReq.urgency || 'обычная',
        requestedByRole: user.role,
        requestedById: user.id,
        selectedSuppliers: [],
      })
    });
    if (!r.ok) {
      let err = ''; try { err = (await r.json()).detail || ''; } catch(_){}
      alert('Не удалось создать заявку' + (err ? ': '+err : ''));
      return;
    }
    // Уведомления по цепочке
    const msg = valid.length>1
      ? ('Заявка из '+valid.length+' позиций — объект '+newSupplyReq.project)
      : ('Заявка «'+valid[0].materialName+'» — объект '+newSupplyReq.project);
    if (user.role === 'мастер' || user.role === 'субподрядчик') {
      notify('Новая заявка от '+user.name+': '+msg, 'supply');
    } else if (user.role === 'прораб') {
      notify('Прораб '+user.name+': '+msg+' — нужно утвердить', 'supply');
    } else {
      notify(msg+' — утверждена директором', 'supply');
    }
    await loadAll();
    setNewSupplyReq({items:[{materialName:'',quantity:'',unit:'шт'}],project:'',urgency:'обычная',notes:'',category:''});
    setShowSupplyForm(false);
  };

  // Сн.5: подсказка цены по материалу (история закупок + каталоги поставщиков)
  const fetchPriceHint = async (name) => {
    const key = (name||'').trim();
    if (!key || key.length < 2 || priceHints[key]) return;
    try {
      const res = await fetch(API+'/material-price-history?material='+encodeURIComponent(key));
      if (!res.ok) return;
      const data = await res.json();
      setPriceHints(prev => ({...prev, [key]: data}));
    } catch(_){}
  };

  // Сн.5: сохранить текущую заявку как шаблон (общий на компанию)
  const saveSupplyTemplate = async () => {
    const valid = (newSupplyReq.items||[]).filter(i=>i.materialName && Number(i.quantity)>0);
    if (!valid.length) { alert('Добавьте хотя бы одну позицию, чтобы сохранить шаблон'); return; }
    const name = window.prompt('Название шаблона (например «Стартовый набор на объект»):', '');
    if (!name || !name.trim()) return;
    const r = await fetch(API+'/supply-request-templates', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({
        name: name.trim(),
        category: newSupplyReq.category || '',
        items: valid.map(it=>({materialName:it.materialName, quantity:Number(it.quantity), unit:it.unit||'шт'})),
        createdBy: user.name, createdById: user.id,
      })
    });
    if (!r.ok) { let e=''; try{e=(await r.json()).detail||'';}catch(_){} alert('Не удалось сохранить шаблон'+(e?': '+e:'')); return; }
    await loadAll();
    alert('Шаблон «'+name.trim()+'» сохранён');
  };

  // Сн.5: подставить шаблон в форму заявки
  const applySupplyTemplate = (tplId) => {
    const tpl = (supplyTemplates||[]).find(t=>String(t.id)===String(tplId));
    if (!tpl) return;
    const items = (tpl.items||[]).map(it=>({materialName:it.materialName, quantity:String(it.quantity||''), unit:it.unit||'шт'}));
    setNewSupplyReq(prev => ({...prev, items: items.length?items:[{materialName:'',quantity:'',unit:'шт'}], category: tpl.category||prev.category}));
  };

  const deleteSupplyTemplate = async (tplId) => {
    if (!window.confirm('Удалить шаблон?')) return;
    await fetch(API+'/supply-request-templates/'+tplId, {method:'DELETE'});
    await loadAll();
  };

  // Ф5a.2: блок «Счета от поставщиков» переехал из Бухгалтерии в раздел Снабжение.
  // Вынесен в функцию, чтобы рендерить из вкладки «Счета». Утверждать/оплачивать может только финансы.
  const renderSupplierInvoices = () => {
    const canPay = isFinanceRole();
    return (<div>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'15px',flexWrap:'wrap',gap:'8px'}}>
                <b style={{color:C.text,fontSize:'15px',fontWeight:'700'}}>📥 Входящие счета от поставщиков</b>
                <button onClick={()=>setNewSupplierInvoice({supplierName:'',projectName:'',invoiceNumber:'',invoiceDate:'',amount:'',vatAmount:'',description:''})} style={btnO}><Plus size={14}/>Новый счёт</button>
              </div>
              {newSupplierInvoice&&(<div style={{...card,padding:'16px',marginBottom:'14px',backgroundColor:C.bg}}>
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:'8px',marginBottom:'8px'}}>
                  <select value={newSupplierInvoice.supplierName} onChange={e=>{const sup=suppliers.find(s=>s.name===e.target.value);setNewSupplierInvoice({...newSupplierInvoice,supplierName:e.target.value,supplierId:sup?sup.id:null});}} style={{...inp,marginBottom:0}}><option value=''>Поставщик *</option>{(suppliers||[]).map(s=><option key={s.id} value={s.name}>{s.name}</option>)}</select>
                  <select value={newSupplierInvoice.projectName} onChange={e=>setNewSupplierInvoice({...newSupplierInvoice,projectName:e.target.value})} style={{...inp,marginBottom:0}}><option value=''>Объект (если по проекту)</option>{projects.map(p=><option key={p.id} value={p.name}>{p.name}</option>)}</select>
                  <input placeholder='№ счёта *' value={newSupplierInvoice.invoiceNumber} onChange={e=>setNewSupplierInvoice({...newSupplierInvoice,invoiceNumber:e.target.value})} style={{...inp,marginBottom:0}}/>
                  <input type='date' value={newSupplierInvoice.invoiceDate} onChange={e=>setNewSupplierInvoice({...newSupplierInvoice,invoiceDate:e.target.value})} style={{...inp,marginBottom:0}}/>
                  <input placeholder='Сумма с НДС (₽) *' type='number' step='any' inputMode='decimal' value={newSupplierInvoice.amount} onChange={e=>setNewSupplierInvoice({...newSupplierInvoice,amount:e.target.value})} style={{...inp,marginBottom:0}}/>
                  <input placeholder='В т.ч. НДС (₽)' type='number' step='any' inputMode='decimal' value={newSupplierInvoice.vatAmount} onChange={e=>setNewSupplierInvoice({...newSupplierInvoice,vatAmount:e.target.value})} style={{...inp,marginBottom:0}}/>
                </div>
                <textarea placeholder='Описание (за что счёт)' value={newSupplierInvoice.description} onChange={e=>setNewSupplierInvoice({...newSupplierInvoice,description:e.target.value})} style={{...inp,minHeight:'50px',marginBottom:'8px'}}/>
                <div style={{display:'flex',gap:'8px'}}>
                  <button onClick={async()=>{
                    if(!newSupplierInvoice.supplierName||!newSupplierInvoice.invoiceNumber||!newSupplierInvoice.amount){alert('Заполните: поставщик, № счёта, сумма');return;}
                    await fetch(API+'/supplier-invoices',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({...newSupplierInvoice,amount:Number(newSupplierInvoice.amount)||0,vatAmount:Number(newSupplierInvoice.vatAmount||0),status:'На утверждении'})});
                    await loadAll(); setNewSupplierInvoice(null);
                  }} style={btnO}><Check size={14}/>Сохранить</button>
                  <button onClick={()=>setNewSupplierInvoice(null)} style={btnG}>Отмена</button>
                </div>
              </div>)}
              {(()=>{const filtered=supplierInvoices.filter(i=>matchSearch(listSearch,i.supplierName,i.invoiceNumber,i.projectName,i.description));const pending=filtered.filter(i=>i.status==='На утверждении');const approved=filtered.filter(i=>i.status==='Утверждён'||i.status==='Частично оплачен');const paid=filtered.filter(i=>i.status==='Оплачен');const totalP=pending.reduce((s,i)=>s+Number(i.amount||0),0);const totalDebt=approved.reduce((s,i)=>s+(Number(i.amount||0)-Number(i.paidAmount||0)),0);
                // Группировка по объектам
                const byProj={};filtered.forEach(inv=>{const pn=inv.projectName||'Без объекта';if(!byProj[pn]) byProj[pn]=[];byProj[pn].push(inv);});
                const projs=Object.keys(byProj).sort();
                return(<div>
                <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(150px,1fr))',gap:'10px',marginBottom:'14px'}}>
                  <div style={{...card,padding:'12px',backgroundColor:C.warningLight}}><p style={{color:C.warning,fontSize:'11px',margin:'0 0 4px'}}>На утверждении</p><b style={{color:C.warning,fontSize:'15px'}}>{pending.length+' · '+Math.round(totalP).toLocaleString('ru-RU')+' ₽'}</b></div>
                  <div style={{...card,padding:'12px',backgroundColor:C.accentLight}}><p style={{color:C.accent,fontSize:'11px',margin:'0 0 4px'}}>К оплате</p><b style={{color:C.accent,fontSize:'15px'}}>{approved.length}</b></div>
                  {totalDebt>0&&<div style={{...card,padding:'12px',backgroundColor:C.dangerLight}}><p style={{color:C.danger,fontSize:'11px',margin:'0 0 4px'}}>⚠️ Долг по счетам</p><b style={{color:C.danger,fontSize:'15px'}}>{Math.round(totalDebt).toLocaleString('ru-RU')+' ₽'}</b></div>}
                  <div style={{...card,padding:'12px',backgroundColor:C.successLight}}><p style={{color:C.success,fontSize:'11px',margin:'0 0 4px'}}>Оплачены</p><b style={{color:C.success,fontSize:'15px'}}>{paid.length}</b></div>
                </div>
                <div style={{position:'relative',marginBottom:'12px'}}>
                  <Search size={13} style={{position:'absolute',left:'10px',top:'50%',transform:'translateY(-50%)',color:C.textMuted}}/>
                  <input placeholder='🔍 Поиск по поставщику, № счёта, объекту' value={listSearch} onChange={e=>setListSearch(e.target.value)} style={{...inp,marginBottom:0,paddingLeft:'30px',fontSize:'12px',padding:'6px 8px 6px 30px'}}/>
                </div>
                {filtered.length===0?<div style={{...card,padding:'30px',textAlign:'center',color:C.textMuted}}>Счетов нет</div>:projs.map(pn=>{const list=byProj[pn];const sumTotal=list.reduce((s,i)=>s+Number(i.amount||0),0);const sumPaid=list.reduce((s,i)=>s+Number(i.paidAmount||0),0);const sumDebt=Math.max(0,sumTotal-sumPaid);const isOpen=expandedProject==='sup-'+pn;return(<div key={pn} style={{...card,marginBottom:'10px'}}>
                  <div style={{padding:'12px 14px',cursor:'pointer',display:'flex',justifyContent:'space-between',alignItems:'center',flexWrap:'wrap',gap:'8px'}} onClick={()=>setExpandedProject(isOpen?null:'sup-'+pn)}>
                    <div>
                      <b style={{color:C.text,fontSize:'13px'}}>🏗 {pn}</b>
                      <p style={{color:C.textSec,margin:'2px 0',fontSize:'11px'}}>{list.length+' счетов · итого '+Math.round(sumTotal).toLocaleString('ru-RU')+' ₽'+(sumPaid>0?' · оплачено '+Math.round(sumPaid).toLocaleString('ru-RU'):'')}</p>
                    </div>
                    <div style={{display:'flex',alignItems:'center',gap:'8px'}}>
                      {sumDebt>0&&<b style={{color:C.danger,fontSize:'13px'}}>{'⚠️ Долг '+Math.round(sumDebt).toLocaleString('ru-RU')+' ₽'}</b>}
                      {isOpen?<ChevronUp size={14}/>:<ChevronDown size={14}/>}
                    </div>
                  </div>
                  {isOpen&&(<div style={{borderTop:'1px solid '+C.border}}>
                    {list.map(inv=>{const total=Number(inv.amount||0);const paid=Number(inv.paidAmount||0);const owe=Math.max(0,total-paid);return(<div key={inv.id} style={{padding:'12px 14px',borderBottom:'1px solid '+C.border,borderLeft:'3px solid '+(inv.status==='Оплачен'?C.success:owe>0&&paid>0?C.warning:inv.status==='Утверждён'?C.accent:C.warning),marginLeft:'10px'}}>
                      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:'10px',flexWrap:'wrap'}}>
                        <div style={{flex:1,minWidth:'200px'}}>
                          <b style={{color:C.text,fontSize:'13px'}}>{inv.supplierName+' · № '+inv.invoiceNumber}</b>
                          <p style={{color:C.textSec,margin:'2px 0',fontSize:'12px'}}>{(inv.invoiceDate||'')+(inv.projectName?' · 🏗 '+inv.projectName:'')+(inv.description?' · '+inv.description:'')}</p>
                          {(inv.offerId||inv.offer_id)&&<p style={{color:C.accent,margin:'2px 0',fontSize:'11px'}}>📨 Создан по выигранному КП #{inv.offerId||inv.offer_id}{inv.materialName?' · '+inv.materialName:''}{inv.paymentTerms?' · условия: '+inv.paymentTerms:''}</p>}
                          <div style={{display:'flex',gap:'10px',marginTop:'4px',flexWrap:'wrap'}}>
                            <span style={{fontSize:'12px',color:C.text}}>{'Сумма: '+Math.round(total).toLocaleString('ru-RU')+' ₽'}</span>
                            {paid>0&&<span style={{fontSize:'12px',color:C.success}}>{'Оплачено: '+Math.round(paid).toLocaleString('ru-RU')+' ₽'}</span>}
                            {owe>0&&paid>0&&<span style={{fontSize:'12px',color:C.danger,fontWeight:'700',padding:'2px 8px',borderRadius:'6px',backgroundColor:C.dangerLight}}>{'⚠️ Недоплата: '+Math.round(owe).toLocaleString('ru-RU')+' ₽'}</span>}
                          </div>
                        </div>
                        <div style={{display:'flex',gap:'4px',alignItems:'center',flexWrap:'wrap'}}>
                          <span style={badge(inv.status==='Оплачен'?C.success:inv.status==='Частично оплачен'?C.warning:inv.status==='Утверждён'?C.accent:C.warning,inv.status==='Оплачен'?C.successLight:inv.status==='Частично оплачен'?C.warningLight:inv.status==='Утверждён'?C.accentLight:C.warningLight,inv.status==='Оплачен'?C.successBorder:inv.status==='Частично оплачен'?C.warningBorder:inv.status==='Утверждён'?C.accentBorder:C.warningBorder)}>{inv.status}</span>
                          {canPay&&inv.status==='На утверждении'&&<button onClick={async()=>{await fetch(API+'/supplier-invoices/'+inv.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:'Утверждён',approvedBy:user.name,approvedAt:new Date().toISOString().split('T')[0]})});await loadAll();}} style={{...btnGr,padding:'4px 8px',fontSize:'11px'}}>✅</button>}
                          {canPay&&(inv.status==='Утверждён'||inv.status==='Частично оплачен')&&owe>0&&<button onClick={async()=>{const ans=prompt('Оплатить (₽). Полная: '+Math.round(owe).toLocaleString('ru-RU')+' ₽',String(owe));if(!ans) return;const sum=toNum(ans);if(sum<=0||sum>owe){alert('Сумма должна быть от 1 до '+Math.round(owe).toLocaleString('ru-RU'));return;}const newPaid=paid+sum;const newStatus=newPaid>=total?'Оплачен':'Частично оплачен';await fetch(API+'/supplier-invoices/'+inv.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:newStatus,paidAmount:newPaid,paidBy:user.name,paidAt:new Date().toISOString().split('T')[0],paidNote:'Оплачено '+Math.round(sum).toLocaleString('ru-RU')+' ₽'})});if(inv.projectName){await fetch(API+'/project-payments',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({projectName:inv.projectName,amount:sum,note:'Оплата счёта '+inv.supplierName+' №'+inv.invoiceNumber,date:new Date().toISOString().split('T')[0],paidBy:user.name})});}await loadAll();}} style={{...btnO,padding:'4px 8px',fontSize:'11px'}}>💰 {owe<total?'Доплатить':'Оплатить'}</button>}
                          {canPay&&<button onClick={async()=>{if(!window.confirm('Удалить?')) return;await fetch(API+'/supplier-invoices/'+inv.id,{method:'DELETE'});await loadAll();}} style={{...btnR,padding:'4px 8px'}}><Trash2 size={11}/></button>}
                        </div>
                      </div>
                    </div>);})}
                  </div>)}
                </div>);})}
              </div>);})()}
    </div>);
  };

  // Парсер items из supply_request: возвращает массив [{materialName, quantity, unit}]
  // Совместим со старыми заявками без itemsJson — там используется одна позиция из material_name
  const parseSupplyItems = (req) => {
    if (!req) return [];
    if (req.itemsJson) {
      try {
        const arr = typeof req.itemsJson === 'string' ? JSON.parse(req.itemsJson) : req.itemsJson;
        if (Array.isArray(arr) && arr.length>0) return arr;
      } catch(_) {}
    }
    // Legacy: одна позиция из материала записи
    if (req.materialName) return [{materialName:req.materialName, quantity:Number(req.quantity)||0, unit:req.unit||'шт'}];
    return [];
  };

  const supplyNoteLines = (req) => String(req?.notes||'').split(/\r?\n/).map(s=>s.trim()).filter(Boolean);
  const supplyNoteValue = (lines, label) => {
    const prefix = String(label||'').toLowerCase()+':';
    const line = (lines||[]).find(l=>l.toLowerCase().startsWith(prefix));
    return line ? line.slice(label.length+1).trim() : '';
  };
  const supplyRequestOrigin = (req) => {
    const lines = supplyNoteLines(req);
    if (!lines.length) return null;
    const notes = lines.join('\n');
    const materialControl = lines.some(l=>l.startsWith('MATERIAL_CONTROL_REQUEST:')) || notes.includes('Создано из контроля материалов');
    const normCoverage = notes.includes('Создано из ведомости') || (notes.includes('Норма:') && notes.includes('Расчётная потребность'));
    if (!materialControl && !normCoverage) return null;
    const projectName = supplyNoteValue(lines,'Объект') || req.project || '';
    const materialName = supplyNoteValue(lines,'Материал') || req.materialName || '';
    const facts = materialControl ? [
      ['План', supplyNoteValue(lines,'План по смете')],
      ['Поставлено', supplyNoteValue(lines,'Поставлено/перемещено')],
      ['Заявки/путь', supplyNoteValue(lines,'В заявках и пути')],
      ['Нехватка', supplyNoteValue(lines,'Расчётная нехватка')],
    ] : [
      ['Смета', supplyNoteValue(lines,'Смета')],
      ['Раздел', supplyNoteValue(lines,'Раздел')],
      ['Работа', supplyNoteValue(lines,'Работа')],
      ['Объём', supplyNoteValue(lines,'Объём работы')],
      ['Норма', supplyNoteValue(lines,'Норма')],
      ['Потребность', supplyNoteValue(lines,'Расчётная потребность')],
    ];
    return {
      type: materialControl ? 'material-control' : 'norm-coverage',
      label: materialControl ? 'Из контроля материалов' : 'Из норм материалов',
      projectName,
      materialName,
      facts: facts.filter(([,v])=>v),
    };
  };
  const openProjectMaterialControl = (projectName) => {
    const project = (projects||[]).find(p=>p.name===projectName);
    if (project) {
      navigateTo('projects');
      setExpandedProject(project.id);
      setActiveProjectTab('Материалы');
      setActiveTabGroup(user?.role==='прораб'?'object':'finance');
    } else {
      navigateTo('warehouse');
      setWarehouseTab('control');
    }
  };
  const renderSupplyRequestOrigin = (req, opts={}) => {
    const origin = supplyRequestOrigin(req);
    if (!origin) return null;
    const color = origin.type==='material-control' ? C.warning : C.info;
    const bg = origin.type==='material-control' ? C.warningLight : C.infoLight;
    const borderColor = origin.type==='material-control' ? C.warningBorder : C.infoBorder;
    const compact = !!opts.compact;
    return (
      <div style={{marginTop:compact?'6px':'8px',padding:compact?'7px 9px':'9px 11px',border:'1.5px solid '+borderColor,borderRadius:'8px',backgroundColor:bg}}>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',gap:'8px',flexWrap:'wrap'}}>
          <b style={{color,fontSize:compact?'11px':'12px'}}>{origin.label}</b>
          {origin.projectName&&<button onClick={e=>{e.stopPropagation();openProjectMaterialControl(origin.projectName);}} style={{...btnG,padding:compact?'3px 7px':'4px 9px',fontSize:compact?'10px':'11px'}}>Открыть контроль</button>}
        </div>
        {!compact&&origin.facts.length>0&&(
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(130px,1fr))',gap:'5px 10px',marginTop:'7px'}}>
            {origin.facts.slice(0,6).map(([k,v])=><div key={k} style={{fontSize:'11px',color:C.textSec}}><span style={{color:C.textMuted}}>{k}: </span><b style={{color:C.text,fontWeight:'600'}}>{v}</b></div>)}
          </div>
        )}
        {compact&&origin.facts.length>0&&<p style={{color:C.textSec,margin:'4px 0 0',fontSize:'11px'}}>{origin.facts.slice(-2).map(([k,v])=>k+': '+v).join(' · ')}</p>}
      </div>
    );
  };

  const supplyMaterialKey = (v) => String(v||'')
    .toLowerCase()
    .replace(/[.,;:()«»"']/g,' ')
    .replace(/\s+/g,' ')
    .trim();
  const supplyUnitKey = (v) => String(v||'')
    .toLowerCase()
    .replace(/[²]/g,'2')
    .replace(/[³]/g,'3')
    .replace(/\s+/g,'')
    .trim();
  const isSameSupplyMaterial = (a,b) => {
    const ak = supplyMaterialKey(a);
    const bk = supplyMaterialKey(b);
    if (!ak || !bk) return false;
    return ak===bk || ak.includes(bk) || bk.includes(ak);
  };
  const supplyPlanningHint = (it, idx) => {
    const projectName = newSupplyReq.project;
    const materialName = (it?.materialName||'').trim();
    if (!projectName || !materialName) return null;
    const rows = materialReconciliationRows(projectName);
    const canonicalName = canonicalMaterialMeta(projectName, materialName).name;
    const row = rows.find(r=>isSameSupplyMaterial(r.name, canonicalName) || isSameSupplyMaterial(r.name, materialName));
    const sameUnit = !row?.unit || !it?.unit || supplyUnitKey(row.unit)===supplyUnitKey(it.unit);
    const draftOther = (newSupplyReq.items||[])
      .filter((x,i)=>i!==idx && isSameSupplyMaterial(x.materialName, materialName))
      .reduce((sum,x)=>sum+toNum(x.quantity),0);
    const planQty = toNum(row?.planQty);
    const supplied = toNum(row?.supplied);
    const stock = toNum(row?.stock);
    const ordered = toNum(row?.requested);
    const inTransit = toNum(row?.inTransit);
    const requested = toNum(it?.quantity);
    const unit = row?.unit || it?.unit || 'шт';
    const recommended = row && planQty>0 && sameUnit ? Math.max(0, toNum(row.toBuy) - draftOther) : null;
    const outsideEstimate = !row || planQty<=0;
    const tooMuch = recommended!==null && requested>0 && requested>recommended+0.0001;
    return {row, unit, sameUnit, planQty, supplied, stock, ordered, inTransit, draftOther, requested, recommended, outsideEstimate, tooMuch};
  };
  const applySupplyRecommendedQty = (idx, hint) => {
    if (!hint || hint.recommended===null) return;
    const qty = Number(hint.recommended.toFixed(3));
    const items = [...(newSupplyReq.items||[])];
    items[idx] = {...items[idx], quantity: String(qty), unit: hint.unit || items[idx].unit || 'шт'};
    setNewSupplyReq({...newSupplyReq, items});
  };
  const renderSupplyPlanningHint = (it, idx) => {
    const hint = supplyPlanningHint(it, idx);
    if (!hint) return null;
    const pill = (label, value, color=C.text) => (
      <span style={{padding:'4px 7px',borderRadius:'8px',backgroundColor:C.bgWhite,border:'1px solid '+C.border,color,fontSize:'11px',whiteSpace:'nowrap'}}>
        {label}: <b>{value}</b>
      </span>
    );
    return (
      <div style={{display:'flex',gap:'6px',flexWrap:'wrap',alignItems:'center',margin:'0 0 8px 2px',padding:'7px 8px',backgroundColor:hint.outsideEstimate?C.warningLight:C.successLight,border:'1px solid '+(hint.outsideEstimate?C.warningBorder:C.successBorder),borderRadius:'8px'}}>
        {hint.outsideEstimate
          ? <span style={{fontSize:'11px',color:C.warning,fontWeight:'700'}}>⚠️ Материала нет в активной смете</span>
          : pill('По смете', fmtMeasure(hint.planQty, hint.unit), C.text)}
        {pill('Поставлено', fmtMeasure(hint.supplied, hint.unit), hint.supplied>0?C.success:C.textSec)}
        {pill('На объекте', fmtMeasure(hint.stock, hint.unit), hint.stock>0?C.success:C.textSec)}
        {hint.ordered>0 && pill('Уже в заявках', fmtMeasure(hint.ordered, hint.unit), C.info)}
        {hint.inTransit>0 && pill('В пути', fmtMeasure(hint.inTransit, hint.unit), C.warning)}
        {hint.draftOther>0 && pill('В этой заявке ещё', fmtMeasure(hint.draftOther, hint.unit), C.info)}
        {hint.recommended!==null && pill('Докупить', fmtMeasure(hint.recommended, hint.unit), hint.recommended>0?C.warning:C.success)}
        {!hint.sameUnit && <span style={{fontSize:'11px',color:C.danger,fontWeight:'700'}}>Ед. изм. отличается от сметы</span>}
        {hint.tooMuch && <span style={{fontSize:'11px',color:C.danger,fontWeight:'700'}}>Заявка больше расчётной потребности</span>}
        {hint.recommended!==null && hint.recommended>0 && (
          <button onClick={()=>applySupplyRecommendedQty(idx, hint)} style={{...btnB,padding:'3px 7px',fontSize:'11px'}}>Подставить {fmtMeasure(hint.recommended, hint.unit)}</button>
        )}
      </div>
    );
  };

  // Парсер itemsKp из supplier_offer: возвращает массив с ценой по каждой позиции
  // Если поставщик заполнил постатейно — вернётся массив. Иначе пусто.
  const parseOfferItems = (offer) => {
    if (!offer) return [];
    if (offer.itemsKpJson) {
      try {
        const arr = typeof offer.itemsKpJson === 'string' ? JSON.parse(offer.itemsKpJson) : offer.itemsKpJson;
        if (Array.isArray(arr) && arr.length>0) return arr;
      } catch(_) {}
    }
    return [];
  };

  const confirmSupplyAsProrab = async (id) => {
    await fetch(API+'/supply-requests/'+id, {
      method:'PUT', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({action:'confirm_prorab', userId:user.id, userName:user.name})
    });
    notify('Заявка подтверждена прорабом — ждёт директора','supply');
    await loadAll();
  };

  const approveSupplyAsDirector = async (id) => {
    await fetch(API+'/supply-requests/'+id, {
      method:'PUT', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({action:'approve_director', userId:user.id, userName:user.name})
    });
    notify('Заявка утверждена директором','supply');
    await loadAll();
  };

  const rejectSupply = async (id) => {
    if (!supplyRejectReason.trim()) { alert('Укажите причину отказа'); return; }
    await fetch(API+'/supply-requests/'+id, {
      method:'PUT', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({action:'reject', rejectReason: supplyRejectReason})
    });
    setSupplyRejectId(null);
    setSupplyRejectReason('');
    notify('Заявка отклонена','supply');
    await loadAll();
  };

  const cancelSupply = async (id) => {
    if (!window.confirm('Отменить заявку?')) return;
    await fetch(API+'/supply-requests/'+id, {
      method:'PUT', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({action:'cancel'})
    });
    await loadAll();
  };

  const loadSupplyStockCheck = async (id) => {
    setSupplyStockCheck(null);
    setSupplyAiText('');
    try {
      const r = await fetch(API+'/supply-requests/'+id+'/stock-check');
      const data = await r.json();
      setSupplyStockCheck(data);
    } catch(_) { setSupplyStockCheck({error:'Не удалось загрузить'}); }
  };

  const askSupplyAi = async (req, stock) => {
    setSupplyAiLoading(true);
    setSupplyAiText('');
    try {
      const prompt = 'Заявка на материал: "'+req.materialName+'" — нужно '+req.quantity+' '+req.unit+
        '. На складе найдено похожих позиций: '+(stock.stockMatches||[]).map(m=>m.name+' ('+m.quantity+' '+m.unit+')').join(', ')+
        '. Дефицит: '+stock.shortage+' '+req.unit+'. Бюджет проекта «'+req.project+'» использован на '+Math.round(stock.budgetRiskPercent||0)+'%. Дай короткий совет директору: стоит ли закупать и сколько, или взять со склада. 2-3 предложения, по-русски.';
      const r = await fetch(API+'/ai-chat',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({messages:[{role:'user',content:prompt}], skipContext:true})});
      const data = await r.json();
      setSupplyAiText((data && data.response) || 'AI не ответил');
    } catch(_) { setSupplyAiText('Ошибка вызова AI'); }
    setSupplyAiLoading(false);
  };

  // === Сн.2: запрос КП у поставщиков ===
  const openRequestKpModal = async (requestId) => {
    setShowRequestKpModal(requestId);
    setSuggestedSuppliers(null);
    setSelectedSupplierIds([]);
    setRequestKpLoading(true);
    try {
      const r = await fetch(API+'/supply-requests/'+requestId+'/suggest-suppliers');
      const data = await r.json();
      if (data.error) {
        setSuggestedSuppliers({suppliers:[], error:data.error});
      } else {
        setSuggestedSuppliers(data);
        // По умолчанию выбираем тех кого AI рекомендует
        setSelectedSupplierIds(data.suppliers.filter(s=>s.aiRecommend&&!s.alreadyRequested).map(s=>s.id));
      }
    } catch(_) {
      setSuggestedSuppliers({suppliers:[], error:'Не удалось загрузить'});
    }
    setRequestKpLoading(false);
  };

  const sendKpRequest = async () => {
    if (!showRequestKpModal || selectedSupplierIds.length===0) { alert('Выберите хотя бы одного поставщика'); return; }
    const aiIds = (suggestedSuppliers?.suppliers||[]).filter(s=>s.aiRecommend).map(s=>s.id);
    const r = await fetch(API+'/supply-requests/'+showRequestKpModal+'/request-kp',{
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({supplierIds:selectedSupplierIds, aiRecommendedIds:aiIds})
    });
    const data = await r.json();
    if (data.error) { alert('Ошибка: '+data.error); return; }
    notify('Отправлен запрос КП '+selectedSupplierIds.length+' поставщикам','supply');
    setShowRequestKpModal(null);
    setSelectedSupplierIds([]);
    setSuggestedSuppliers(null);
    await loadAll();
  };

  const selectSupplierOffer = async (offerId) => {
    if (!window.confirm('Выбрать это КП? Остальные КП по этой заявке будут отклонены.')) return;
    await fetch(API+'/supplier-offers/'+offerId,{
      method:'PUT', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({action:'select'})
    });
    notify('КП утверждено директором','supply');
    await loadAll();
  };

  const rejectSupplierOffer = async (offerId) => {
    if (!window.confirm('Отклонить это КП?')) return;
    await fetch(API+'/supplier-offers/'+offerId,{
      method:'PUT', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({action:'reject'})
    });
    await loadAll();
  };

  // Сн.3: AI сравнение КП по заявке
  const runCompareKp = async (reqId) => {
    setCompareLoadingReqId(reqId);
    try {
      const r = await fetch(API+'/supply-requests/'+reqId+'/compare-kp');
      const data = await r.json();
      setCompareResultByReq(prev=>({...prev, [reqId]: data}));
    } catch(e) {
      setCompareResultByReq(prev=>({...prev, [reqId]: {error:'Не удалось получить сравнение'}}));
    }
    setCompareLoadingReqId(null);
  };

  // Сн.3: создать счёт от поставщика по выигранному КП
  const createInvoiceFromOffer = async (offerId) => {
    if (!newOfferInvoice.invoiceNumber || !newOfferInvoice.amount) { alert('Заполните номер счёта и сумму'); return; }
    const r = await fetch(API+'/supplier-offers/'+offerId+'/create-invoice', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({
        invoiceNumber: newOfferInvoice.invoiceNumber,
        invoiceDate: newOfferInvoice.invoiceDate,
        amount: Number(newOfferInvoice.amount),
        vatAmount: Number(newOfferInvoice.vatAmount || 0),
        description: newOfferInvoice.description,
        fileUrl: newOfferInvoice.fileUrl,
      })
    });
    const data = await r.json();
    if (data.error) { alert('Ошибка: '+data.error); return; }
    notify('Счёт выставлен — ждёт оплаты бухгалтером','supply');
    setInvoicingOfferId(null);
    setNewOfferInvoice({invoiceNumber:'',invoiceDate:new Date().toISOString().split('T')[0],amount:'',vatAmount:'',description:'',fileUrl:''});
    await loadAll();
  };

  // Сн.4: поставщик отгружает выигранное КП
  const createShipmentFromOffer = async (offer) => {
    const req = supplyRequests.find(r=>r.id===offer.requestId);
    const qty = shipmentForm.shippedQuantity || req?.quantity || '';
    if (!qty) { alert('Укажите количество отгрузки'); return; }
    const r = await fetch(API+'/supplier-offers/'+offer.id+'/ship', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({
        shippedQuantity: Number(qty),
        waybillNumber: shipmentForm.waybillNumber,
        waybillDate: shipmentForm.waybillDate,
        vehicleNumber: shipmentForm.vehicleNumber,
        driverName: shipmentForm.driverName,
        documentUrl: shipmentForm.documentUrl,
        photoUrl: shipmentForm.photoUrl,
      })
    });
    const data = await r.json();
    if (data.detail || data.error) { alert('Ошибка: '+(data.detail||data.error)); return; }
    notify('Поставка отгружена — ждёт приёмки','delivery');
    setShippingOfferId(null);
    setShipmentForm({shippedQuantity:'',waybillNumber:'',waybillDate:new Date().toISOString().split('T')[0],vehicleNumber:'',driverName:'',documentUrl:'',photoUrl:''});
    await loadAll();
  };

  const receiveSupplyDelivery = async (delivery) => {
    if (!receiveForm.receivedQuantity && receiveForm.receivedQuantity!==0) { alert('Укажите принятое количество'); return; }
    const r = await fetch(API+'/supply-deliveries/'+delivery.id+'/receive', {
      method:'PUT', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({
        receivedQuantity: Number(receiveForm.receivedQuantity),
        qualityStatus: receiveForm.qualityStatus,
        qualityNotes: receiveForm.qualityNotes,
        photoUrl: receiveForm.photoUrl,
        claimDescription: receiveForm.claimDescription,
        receivedBy: user.name,
      })
    });
    const data = await r.json();
    if (data.detail || data.error) { alert('Ошибка: '+(data.detail||data.error)); return; }
    notify((data.claimId?'Приёмка с претензией':'Поставка принята')+(data.invoiceId?' · создана накладная #'+data.invoiceId:''),'delivery');
    setReceivingDeliveryId(null);
    setReceiveForm({receivedQuantity:'',qualityStatus:'Принято',qualityNotes:'',photoUrl:'',claimDescription:''});
    await loadAll();
  };

  const runDeliveryAiCheck = async (delivery, parsedItems=[]) => {
    setDeliveryAiLoadingId(delivery.id);
    try {
      const r = await fetch(API+'/supply-deliveries/'+delivery.id+'/ai-check', {
        method:'POST', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({parsedItems})
      });
      const data = await r.json();
      setDeliveryAiResultById(prev=>({...prev, [delivery.id]: data.result || 'AI не ответил'}));
    } catch(e) {
      setDeliveryAiResultById(prev=>({...prev, [delivery.id]: 'AI-сверка не сработала'}));
    }
    setDeliveryAiLoadingId(null);
  };

  const saveOffer = async (requestId) => {
    if (!newOffer.supplierId||!newOffer.pricePerUnit||!newOffer.deliveryDays) { alert('Заполните все поля включая срок поставки'); return; }
    const req = supplyRequests.find(r=>r.id===requestId);
    await fetch(API+'/supplier-offers',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({requestId,supplierId:Number(newOffer.supplierId),pricePerUnit:Number(newOffer.pricePerUnit),totalPrice:Number(newOffer.pricePerUnit)*(req?req.quantity:1),deliveryDays:Number(newOffer.deliveryDays),notes:newOffer.notes})});
    await loadAll(); setNewOffer({supplierId:'',pricePerUnit:'',deliveryDays:'',notes:''});
  };

  const approveOffer = async (offer) => {
    await fetch(API+'/supplier-offers/'+offer.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:'Утверждено'})});
    await fetch(API+'/supply-requests/'+offer.requestId,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({status:'Утверждено'})});
    const req = supplyRequests.find(r=>r.id===offer.requestId);
    await fetch(API+'/supply-history',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({supplierId:offer.supplierId,materialName:req?req.materialName:'',quantity:req?req.quantity:0,unit:req?req.unit:'',pricePerUnit:offer.pricePerUnit,totalPrice:offer.totalPrice,project:req?req.project:'',date:new Date().toISOString().split('T')[0],status:'Ожидает поставки'})});
    notify('КП утверждено','supply'); await loadAll();
  };

  const deleteContract = async (id) => { if (window.confirm('Удалить?')) { await fetch(API+'/contracts/'+id,{method:'DELETE'}); await loadAll(); } };
  const deleteInterimAct = async (id) => { if (window.confirm('Удалить?')) { await fetch(API+'/interim-acts/'+id,{method:'DELETE'}); await loadAll(); } };

  const toggleDay = async (staffId,day) => {
    await fetch(API+'/timesheet',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({staffId,day})});
    setTimesheet(prev=>({...prev,[staffId+'-'+day]:!prev[staffId+'-'+day]}));
  };

  const createContract = async () => {
    if (!newContract.masterId||!newContract.contractNumber||!newContract.project) return;
    await fetch(API+'/contracts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(newContract)});
    await loadAll(); setNewContract({masterId:'',masterName:'',contractType:'ГПХ',contractNumber:'',project:'',startDate:'',endDate:''}); setShowForm(false);
  };

  const createInterimAct = async () => {
    if (!newAct.masterId||!newAct.project||!newAct.periodStart||!newAct.periodEnd) return;
    const mw = workJournal.filter(j=>j.masterId===Number(newAct.masterId)&&j.project===newAct.project&&j.status==='Подтверждено');
    const total = mw.reduce((s,w)=>s+w.total,0);
    const contract = contracts.find(c=>c.masterId===Number(newAct.masterId)&&c.project===newAct.project);
    await fetch(API+'/interim-acts',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({...newAct,masterId:Number(newAct.masterId),contractId:contract?contract.id:null,totalAmount:total,paidAmount:0})});
    notify('Акт создан: '+newAct.masterName,'act');
    await loadAll(); setNewAct({masterId:'',masterName:'',project:'',periodStart:'',periodEnd:''}); setShowForm(false);
  };

  const saveRoom = async () => {
    if (!newRoom.name||!newRoom.project) return;
    const data = {project:newRoom.project,name:newRoom.name,floor:Number(newRoom.floor)||1,liter:newRoom.liter||'',roomType:newRoom.roomType||'Комната',floorArea:Number(newRoom.floorArea)||0,wallArea:Number(newRoom.wallArea)||0,ceilingArea:Number(newRoom.ceilingArea)||0,height:Number(newRoom.height)||0,ceilingType:newRoom.ceilingType,wallMaterial:newRoom.wallMaterial,floorMaterial:newRoom.floorMaterial,windows:0,doors:0,notes:newRoom.notes};
    if (editingItem) {
      await fetch(API+'/rooms/'+editingItem.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
    } else {
      if(newRoom.roomType&&!['Комната','Кабинет','Коридор','Санузел','Кухня','Балкон','Лестница','Холл','Техническое'].includes(newRoom.roomType)){const updated=[...new Set([...customRoomTypes,newRoom.roomType])];setCustomRoomTypes(updated);localStorage.setItem('customRoomTypes',JSON.stringify(updated));}
      await fetch(API+'/rooms',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
    }
    await loadAll(); setNewRoom({project:'',name:'',floor:'',liter:'',roomType:'Комната',floorArea:'',wallArea:'',ceilingArea:'',height:'',ceilingType:'Простой',wallMaterial:'Штукатурка',floorMaterial:'Стяжка',notes:''}); setEditingItem(null); setShowRoomForm(false);
  };

  const deleteRoom = async (id) => { if (window.confirm('Удалить?')) { await fetch(API+'/rooms/'+id,{method:'DELETE'}); await loadAll(); } };

  const saveWindow = async (roomId) => {
    if (!newWindow.width||!newWindow.height) return;
    try {
      await fetch(API+'/room-windows',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({...newWindow,roomId:Number(roomId)})});
      const rwin = await fetch(API+'/room-windows').then(r=>r.json()).catch(()=>[]);
      setRoomWindows(Array.isArray(rwin)?rwin:[]);
    } catch(e) {
      const win = {...newWindow,id:Date.now(),room_id:Number(roomId)};
      setRoomWindows(prev=>[...prev,win]);
    }
    setNewWindow({roomId:'',name:'Окно '+(roomWindows.filter(w=>w.room_id===roomId).length+2),width:'',height:'',windowType:'ПВХ',revealDepth:'',revealMaterial:'Штукатурка'});
  };

  const updateWindow = async (win) => {
    try {
      await fetch(API+'/room-windows/'+win.id,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(win)});
      const rwin = await fetch(API+'/room-windows').then(r=>r.json()).catch(()=>[]);
      setRoomWindows(Array.isArray(rwin)?rwin:[]);
    } catch(e) {}
    setEditingWindow(null);
  };

  const deleteWindow = async (id) => {
    try {
      await fetch(API+'/room-windows/'+id,{method:'DELETE'});
      setRoomWindows(prev=>prev.filter(w=>w.id!==id));
    } catch(e) { setRoomWindows(prev=>prev.filter(w=>w.id!==id)); }
  };

