              await loadAll();
              const newPl=await fetch(API+'/pricelists').then(r=>r.json()).then(arr=>(Array.isArray(arr)?arr.find(p=>p.id===data.id):null));
              if(newPl){setSelectedPricelist(newPl);await loadPricelistItems(newPl.id);}
